963	class BinParser {
964	  constructor(binData) {
965	    this.binData = binData; // ArrayBuffer
966	  }
967	
968	  // 读取指定地址的字符串（固定长度）
969	  readString(address, length) {
970	    const view = new DataView(this.binData);
971	    let str = '';
972	    for (let i = 0; i < length; i++) {
973	      const charCode = view.getUint8(address + i);
974	      if (charCode === 0) break; // 遇到结束符停止
975	      str += String.fromCharCode(charCode);
976	    }
977	    return str.trim();
978	  }
979	
980	  // 读取序列号
981	  getSerialNumber() {
982	    return this.readString(BIN_ADDRESS.SERIAL_NUMBER, 16);
983	  }
984	
985	  // 读取型号
986	  getModel() {
987	    return this.readString(BIN_ADDRESS.MODEL, 16);
988	  }
989	
990	  // 读取物料号
991	  getMaterialNumber() {
992	    const view = new DataView(this.binData);
993	    return view.getUint16(BIN_ADDRESS.MATERIAL_NUMBER, true); // 小端序
994	  }
995	
996	  // 检查是否有听力图数据
997	  hasAudiogram() {
998	    const view = new DataView(this.binData);
999	    // 检查听力图数据地址是否有有效数据
1000	    // 具体判断逻辑需根据固件协议确定
1001	    // 这里假设如果地址处有非0xFF数据则认为有效
1002	    for (let i = 0; i < 128; i++) {
1003	      const byte = view.getUint8(BIN_ADDRESS.AUDIOGRAM_DATA + i);
1004	      if (byte !== 0xFF && byte !== 0x00) {
1005	        return true;
1006	      }
1007	    }
1008	    return false;
1009	  }
1010	
1011	  // 获取听力图数据
1012	  getAudiogramData() {
1013	    if (!this.hasAudiogram()) {
1014	      return null;
1015	    }
1016	    // 提取听力图数据
1017	    // 具体格式需根据固件协议确定
1018	    const view = new DataView(this.binData);
1019	    const audiogramSize = 128; // 假设128字节
1020	    const data = new Uint8Array(audiogramSize);
1021	    for (let i = 0; i < audiogramSize; i++) {
1022	      data[i] = view.getUint8(BIN_ADDRESS.AUDIOGRAM_DATA + i);
1023	    }
1024	    return data.buffer;
1025	  }
