1374	          url: '/pages/info-form/info-form?fitted=false'
1375	        });
1376	      }
1377	
1378	    } catch (err) {
1379	      wx.hideLoading();
1380	      console.error('连接失败', err);
1381	      wx.showToast({
1382	        title: '连接失败，请重试',
1383	        icon: 'none'
1384	      });
1385	    }
1386	  },
1387	
1388	  readFullBin() {
1389	    return new Promise((resolve, reject) => {
1390	      // 监听数据
1391	      const chunks = [];
1392	      bleService.onBLECharacteristicValueChange(res => {
1393	        chunks.push(res.value);
1394	      });
1395	
1396	      // 发送读取命令
1397	      const cmdBuffer = new ArrayBuffer(1);
1398	      const cmdView = new DataView(cmdBuffer);
1399	      cmdView.setUint8(0, 0xF8);
1400	      bleService.writeBLECharacteristicValue(cmdBuffer);
1401	
1402	      // 合并分片数据（实际协议需根据固件确定）
1403	      setTimeout(() => {
1404	        if (chunks.length > 0) {
1405	          const totalLength = chunks.reduce((sum, buf) => sum + buf.byteLength, 0);
1406	          const combined = new ArrayBuffer(totalLength);
1407	          const combinedView = new DataView(combined);
1408	          let offset = 0;
1409	          for (const chunk of chunks) {
1410	            const chunkView = new DataView(chunk);
1411	            for (let i = 0; i < chunk.byteLength; i++) {
1412	              combinedView.setUint8(offset++, chunkView.getUint8(i));
1413	            }
1414	          }
1415	          resolve(combined);
1416	        } else {
1417	          reject(new Error('未收到数据'));
1418	        }
1419	      }, 2000);
1420	    });
1421	  }
1422	});
