- [ ] **Step 2: 创建 launch.js**

```javascript
// 启动页逻辑
const app = getApp();

Page({
  data: {
    canUseGetPhoneNumber: true
  },

  onLoad() {
    // 检查是否已登录，已登录则直接跳转
    if (!app.globalData.isFirstLaunch) {
      wx.redirectTo({
        url: '/pages/guide/guide'
      });
    }
  },

  onGetPhoneNumber(e) {
    if (e.detail.errMsg === 'getPhoneNumber:ok') {
      // 获取到手机号，调用云开发登录
      this.doLogin(e.detail.code);
    } else {
      wx.showToast({
        title: '请允许授权',
        icon: 'none'
      });
    }
  },

  doLogin(code) {
    wx.showLoading({ title: '登录中...' });

    // TODO: 调用云开发云函数或自建服务器登录
    // 临时存储，后续迁移
    wx.cloud.init();
    wx.cloud.callFunction({
      name: 'login',
      data: { code }
    }).then(res => {
      wx.hideLoading();
      if (res.result.openid) {
        app.globalData.openid = res.result.openid;
        app.globalData.isFirstLaunch = false;
        wx.setStorageSync('openid', res.result.openid);
        wx.redirectTo({
          url: '/pages/guide/guide'
        });
      }
    }).catch(err => {
      wx.hideLoading();
      // 接口未就绪时，模拟登录成功用于本地调试
      app.globalData.openid = 'test_openid_' + Date.now();
      app.globalData.isFirstLaunch = false;
      wx.setStorageSync('openid', app.globalData.openid);
      wx.redirectTo({
        url: '/pages/guide/guide'
      });
    });
  },

  onSkip() {
    // 暂不登录，跳转到引导页
    wx.redirectTo({
      url: '/pages/guide/guide'
    });
  }
});
