// 常量定义

// BLE UUID 配置（需与固件匹配）
const BLE_UUID = {
  // 标准 BLE 服务
  DEVICE_INFO_SERVICE: '180A',
  BATTERY_SERVICE: '180F',

  // 自定义服务（需与固件厂商确认）
  CUSTOM_SERVICE: '0000FFE0-0000-1000-8000-00805F9B34FB',
  CUSTOM_CHAR_WRITE: '0000FFE1-0000-1000-8000-00805F9B34FB',
  CUSTOM_CHAR_READ: '0000FFE2-0000-1000-8000-00805F9B34FB',

  // 厂商自定义
  VENDOR_SERVICE: '0000FFF0-0000-1000-8000-00805F9B34FB',
  VENDOR_CHAR: '0000FFF1-0000-1000-8000-00805F9B34FB'
};

// Bin 数据地址映射
const BIN_ADDRESS = {
  // 序列号地址（16字节）
  SERIAL_NUMBER: 0x1FE0,
  // 型号地址（16字节）
  MODEL: 0x1FF0,
  // 物料号地址
  MATERIAL_NUMBER: 0x7FFA,
  // 听力图数据地址
  AUDIOGRAM_DATA: 0x1DB7,
  // 音量配置地址
