// BLE 蓝牙通信服务

const { BLE_UUID, BLE_CMD } = require('../utils/constants');

class BLEService {
  constructor() {
    this.deviceId = null;
    this.serviceId = null;
    this.writeCharId = null;
    this.readCharId = null;
    this.isConnected = false;
  }

  // 初始化蓝牙适配器
  openBluetoothAdapter() {
    return new Promise((resolve, reject) => {
      wx.openBluetoothAdapter({
        success: res => {
          console.log('蓝牙适配器已打开');
          resolve(res);
        },
        fail: err => {
          console.error('打开蓝牙适配器失败', err);
          reject(err);
        }
      });
    });
  }

  // 开始搜索设备
  startBluetoothDevicesDiscovery() {
    return new Promise((resolve, reject) => {
      wx.startBluetoothDevicesDiscovery({
        services: [BLE_UUID.VENDOR_SERVICE, BLE_UUID.CUSTOM_SERVICE],
        allowDuplicatesKey: false,
        success: res => {
          console.log('开始搜索设备');
          resolve(res);
        },
        fail: err => {
          console.error('搜索设备失败', err);
          reject(err);
        }
      });
    });
  }

  // 获取已发现的设备
  getBluetoothDevices() {
    return new Promise((resolve, reject) => {
      wx.getBluetoothDevices({
        success: res => {
          console.log('已发现设备数:', res.devices.length);
          resolve(res.devices);
        },
        fail: err => {
          console.error('获取设备列表失败', err);
          reject(err);
        }
      });
    });
  }

  // 停止搜索
  stopBluetoothDevicesDiscovery() {
    return new Promise((resolve, reject) => {
      wx.stopBluetoothDevicesDiscovery({
        success: res => {
          console.log('停止搜索');
          resolve(res);
        },
        fail: err => {
          reject(err);
        }
      });
    });
  }

  // 连接设备
  createBLEConnection(deviceId) {
    wx.showLoading({ title: '连接中...' });
    return new Promise((resolve, reject) => {
      wx.createBLEConnection({
        deviceId,
        success: res => {
          console.log('连接成功', deviceId);
          this.deviceId = deviceId;
          this.isConnected = true;
          wx.hideLoading();
          // 获取服务
          this.getBLEDeviceServices(deviceId).then(resolve).catch(reject);
        },
        fail: err => {
          console.error('连接失败', err);
          wx.hideLoading();
          reject(err);
        }
      });
    });
  }

  // 获取设备服务
  getBLEDeviceServices(deviceId) {
    return new Promise((resolve, reject) => {
      wx.getBLEDeviceServices({
        deviceId,
        success: res => {
          console.log('服务列表', res.services);
          // 查找自定义服务
          const service = res.services.find(s =>
            s.uuid === BLE_UUID.CUSTOM_SERVICE ||
            s.uuid === BLE_UUID.VENDOR_SERVICE
          );
          if (service) {
            this.serviceId = service.uuid;
            this.getBLEDeviceCharacteristics(deviceId, service.uuid)
              .then(resolve)
              .catch(reject);
          } else {
            reject(new Error('未找到目标服务'));
          }
        },
        fail: err => {
          reject(err);
        }
      });
    });
  }

  // 获取特征值
  getBLEDeviceCharacteristics(deviceId, serviceId) {
    return new Promise((resolve, reject) => {
      wx.getBLEDeviceCharacteristics({
        deviceId,
        serviceId,
        success: res => {
          console.log('特征值列表', res.characteristics);
          for (const char of res.characteristics) {
            if (char.properties.write) {
              this.writeCharId = char.uuid;
            }
            if (char.properties.read || char.properties.notify) {
              this.readCharId = char.uuid;
            }
          }
          resolve();
        },
        fail: err => {
          reject(err);
        }
      });
    });
  }

  // 写入数据
  writeBLECharacteristicValue(buffer) {
    return new Promise((resolve, reject) => {
      if (!this.deviceId || !this.serviceId || !this.writeCharId) {
        reject(new Error('未连接设备'));
        return;
      }
      wx.writeBLECharacteristicValue({
        deviceId: this.deviceId,
        serviceId: this.serviceId,
        characteristicId: this.writeCharId,
        value: buffer,
        success: res => {
          console.log('写入成功');
          resolve(res);
        },
        fail: err => {
          console.error('写入失败', err);
          reject(err);
        }
      });
    });
  }

  // 读取数据
  readBLECharacteristicValue() {
    return new Promise((resolve, reject) => {
      if (!this.deviceId || !this.serviceId || !this.readCharId) {
        reject(new Error('未连接设备'));
        return;
      }
      wx.readBLECharacteristicValue({
        deviceId: this.deviceId,
        serviceId: this.serviceId,
        characteristicId: this.readCharId,
        success: res => {
          resolve(res);
        },
        fail: err => {
          reject(err);
        }
      });
    });
  }

  // 监听特征值变化
  onBLECharacteristicValueChange(callback) {
    wx.onBLECharacteristicValueChange(res => {
      console.log('收到数据', res);
      callback(res);
    });
  }

  // 启用特征值通知
  notifyBLECharacteristicValueChange() {
    return new Promise((resolve, reject) => {
      wx.notifyBLECharacteristicValueChange({
        deviceId: this.deviceId,
        serviceId: this.serviceId,
        characteristicId: this.readCharId,
        state: true,
        success: res => {
          console.log('已启用通知');
          resolve(res);
        },
        fail: err => {
          reject(err);
        }
      });
    });
  }

  // 断开连接
  closeBLEConnection() {
    if (this.deviceId) {
      wx.closeBLEConnection({
        deviceId: this.deviceId
      });
      this.deviceId = null;
      this.isConnected = false;
    }
  }

  // 关闭适配器
  closeBluetoothAdapter() {
    wx.closeBluetoothAdapter();
  }
}

module.exports = new BLEService();
