```javascript
// Bin 数据解析器

const { BIN_ADDRESS } = require('../utils/constants');

class BinParser {
  constructor(binData) {
    this.binData = binData; // ArrayBuffer
  }

  // 读取指定地址的字符串（固定长度）
  readString(address, length) {
    const view = new DataView(this.binData);
    let str = '';
    for (let i = 0; i < length; i++) {
      const charCode = view.getUint8(address + i);
      if (charCode === 0) break; // 遇到结束符停止
      str += String.fromCharCode(charCode);
    }
    return str.trim();
  }

  // 读取序列号
  getSerialNumber() {
    return this.readString(BIN_ADDRESS.SERIAL_NUMBER, 16);
  }

  // 读取型号
  getModel() {
    return this.readString(BIN_ADDRESS.MODEL, 16);
  }

  // 读取物料号
  getMaterialNumber() {
    const view = new DataView(this.binData);
    return view.getUint16(BIN_ADDRESS.MATERIAL_NUMBER, true); // 小端序
  }

  // 检查是否有听力图数据
  hasAudiogram() {
    const view = new DataView(this.binData);
    // 检查听力图数据地址是否有有效数据
    // 具体判断逻辑需根据固件协议确定
    // 这里假设如果地址处有非0xFF数据则认为有效
    for (let i = 0; i < 128; i++) {
      const byte = view.getUint8(BIN_ADDRESS.AUDIOGRAM_DATA + i);
      if (byte !== 0xFF && byte !== 0x00) {
        return true;
      }
    }
    return false;
  }

  // 获取听力图数据
  getAudiogramData() {
    if (!this.hasAudiogram()) {
      return null;
    }
    // 提取听力图数据
    // 具体格式需根据固件协议确定
    const view = new DataView(this.binData);
    const audiogramSize = 128; // 假设128字节
    const data = new Uint8Array(audiogramSize);
    for (let i = 0; i < audiogramSize; i++) {
      data[i] = view.getUint8(BIN_ADDRESS.AUDIOGRAM_DATA + i);
    }
    return data.buffer;
  }

  // 获取完整设备信息
  getDeviceInfo() {
    return {
      serialNumber: this.getSerialNumber(),
      model: this.getModel(),
      materialNumber: this.getMaterialNumber(),
      hasAudiogram: this.hasAudiogram(),
      audiogramData: this.getAudiogramData()
    };
  }

  // 获取音量配置（4种模式）
  getVolumeConfig() {
    const view = new DataView(this.binData);
    const volumes = [];
    for (let i = 0; i < 4; i++) {
      const addr = BIN_ADDRESS.VOL_ADDR + i * 0x2000; // 每种模式间隔8KB
      volumes.push({
        mode: i,
        min: view.getUint8(addr),
        max: view.getUint8(addr + 1),
        current: view.getUint8(addr + 2)
      });
    }
    return volumes;
  }
}

// 解析 bin 文件（32KB）
function parseBin(binBuffer) {
  const parser = new BinParser(binBuffer);
  return parser.getDeviceInfo();
}

// 检查 bin 中是否有听力图
function checkHasAudiogram(binBuffer) {
  const parser = new BinParser(binBuffer);
  return parser.hasAudiogram();
}

module.exports = {
  BinParser,
  parseBin,
  checkHasAudiogram
};
```

