// 设备扫描页逻辑
const bleService = require('../../services/ble-service');
const { parseBin, checkHasAudiogram } = require('../../services/bin-parser');
const app = getApp();

Page({
  data: {
    isScanning: false,
    devices: [],
    selectedDevice: null,
    fitted: true // 已验配/未验配路径
  },

  onLoad(options) {
    if (options.fitted) {
      this.data.fitted = options.fitted === 'true';
    }
  },

  onShow() {
    // 页面显示时检查蓝牙适配器状态
    this.checkBluetoothState();
  },

  onHide() {
    // 停止扫描
    if (this.data.isScanning) {
      this.onStopScan();
    }
  },

  onUnload() {
    // 断开连接
    bleService.closeBLEConnection();
  },

  checkBluetoothState() {
    wx.getBluetoothAdapterState({
      success: res => {
        console.log('蓝牙适配器状态', res);
        if (!res.available) {
          wx.showToast({
            title: '蓝牙不可用',
            icon: 'none'
          });
        }
      },
      fail: err => {
        console.error('获取蓝牙状态失败', err);
      }
    });
  },

  async onStartScan() {
    try {
      // 打开适配器
      await bleService.openBluetoothAdapter();

      // 开始搜索
      await bleService.startBluetoothDevicesDiscovery();
      this.data.isScanning = true;
      this.setData({ isScanning: true });

      // 监听发现设备
      wx.onBluetoothDeviceFound(res => {
        console.log('发现设备', res);
        this.addDevice(res.devices[0]);
      });

      // 10秒后自动停止
      setTimeout(() => {
        if (this.data.isScanning) {
          this.onStopScan();
        }
      }, 10000);

    } catch (err) {
      console.error('扫描失败', err);
      wx.showToast({
        title: '扫描失败，请重试',
        icon: 'none'
      });
    }
  },

  onStopScan() {
    bleService.stopBluetoothDevicesDiscovery();
    this.data.isScanning = false;
    this.setData({ isScanning: false });
    wx.offBluetoothDeviceFound(); // 取消监听
  },

  addDevice(device) {
    // 过滤设备名
    if (!device.name && !device.localName) return;

    const existing = this.data.devices.find(d => d.deviceId === device.deviceId);
    if (existing) return;

    this.data.devices.push({
      deviceId: device.deviceId,
      name: device.name || device.localName,
      sn: '', // 待读取
      selected: false,
      rssi: device.RSSI
    });

    this.setData({ devices: this.data.devices });

    // 尝试连接并读取SN
    this.readDeviceSN(device.deviceId);
  },

  async readDeviceSN(deviceId) {
    try {
      // 连接到设备
      await bleService.createBLEConnection(deviceId);

      // 启用通知
      await bleService.notifyBLECharacteristicValueChange();

      // 监听数据返回
      bleService.onBLECharacteristicValueChange(res => {
        const binData = res.value;
        try {
          const parser = parseBin(binData);
          const sn = parser.getSerialNumber();

          // 更新设备列表中的SN
          const device = this.data.devices.find(d => d.deviceId === deviceId);
          if (device) {
            device.sn = sn;
            this.setData({ devices: this.data.devices });
          }
        } catch (e) {
          console.error('解析bin数据失败', e);
        }
      });

      // 发送读取命令（0xF8）
      const cmdBuffer = new ArrayBuffer(1);
      const cmdView = new DataView(cmdBuffer);
      cmdView.setUint8(0, 0xF8);
      await bleService.writeBLECharacteristicValue(cmdBuffer);

    } catch (err) {
      console.error('读取SN失败', err);
    }
  },

  onSelectDevice(e) {
    const device = e.currentTarget.dataset.device;
    // 更新选中状态
    this.data.devices.forEach(d => d.selected = false);
    device.selected = true;
    this.setData({
      devices: this.data.devices,
      selectedDevice: device
    });
  },

  async onConnect() {
    if (!this.data.selectedDevice) {
      wx.showToast({ title: '请先选择设备', icon: 'none' });
      return;
    }

    wx.showLoading({ title: '连接中...' });

    try {
      await bleService.createBLEConnection(this.data.selectedDevice.deviceId);

      // 连接成功后，获取完整bin数据
      const binData = await this.readFullBin();

      // 解析设备信息
      const deviceInfo = parseBin(binData);

      // 存储设备信息到全局
      app.globalData.deviceInfo = {
        ...this.data.selectedDevice,
        ...deviceInfo
      };

      wx.hideLoading();

      // 根据路径跳转
      if (this.data.fitted) {
        // 已验配路径：检查是否有听力图
        if (deviceInfo.hasAudiogram) {
          // 有听力图，跳转到信息填写页
          wx.redirectTo({
            url: '/pages/info-form/info-form?fitted=true'
          });
        } else {
          // 无听力图，提示并返回引导页
          wx.showModal({
            title: '提示',
            content: '该助听器未完成验配，请选择"未验配"路径',
            showCancel: false,
            success: () => {
              wx.redirectTo({
                url: '/pages/guide/guide'
              });
            }
          });
        }
      } else {
        // 未验配路径：跳转到信息填写页
        wx.redirectTo({
          url: '/pages/info-form/info-form?fitted=false'
        });
      }

    } catch (err) {
      wx.hideLoading();
      console.error('连接失败', err);
      wx.showToast({
        title: '连接失败，请重试',
        icon: 'none'
      });
    }
  },

  readFullBin() {
    return new Promise((resolve, reject) => {
      // 监听数据
      const chunks = [];
      bleService.onBLECharacteristicValueChange(res => {
        chunks.push(res.value);
      });

      // 发送读取命令
      const cmdBuffer = new ArrayBuffer(1);
      const cmdView = new DataView(cmdBuffer);
      cmdView.setUint8(0, 0xF8);
      bleService.writeBLECharacteristicValue(cmdBuffer);

      // 合并分片数据（实际协议需根据固件确定）
      setTimeout(() => {
        if (chunks.length > 0) {
          const totalLength = chunks.reduce((sum, buf) => sum + buf.byteLength, 0);
          const combined = new ArrayBuffer(totalLength);
          const combinedView = new DataView(combined);
          let offset = 0;
          for (const chunk of chunks) {
            const chunkView = new DataView(chunk);
            for (let i = 0; i < chunk.byteLength; i++) {
              combinedView.setUint8(offset++, chunkView.getUint8(i));
            }
          }
          resolve(combined);
        } else {
          reject(new Error('未收到数据'));
        }
      }, 2000);
    });
  }
});
