```javascript
// 信息填写页逻辑
const apiService = require('../../services/api-service');
const app = getApp();

Page({
  data: {
    fitted: true,
    formData: {
      name: '',
      phone: '',
      store: ''
    },
    deviceInfo: null,
    canSubmit: false
  },

  onLoad(options) {
    this.data.fitted = options.fitted === 'true';
    this.data.deviceInfo = app.globalData.deviceInfo;
    this.setData({
      fitted: this.data.fitted,
      deviceInfo: this.data.deviceInfo
    });
    this.checkCanSubmit();
  },

  onInputName(e) {
    this.data.formData.name = e.detail.value;
    this.checkCanSubmit();
  },

  onInputPhone(e) {
    this.data.formData.phone = e.detail.value;
    this.checkCanSubmit();
  },

  onInputStore(e) {
    this.data.formData.store = e.detail.value;
    this.checkCanSubmit();
  },

  checkCanSubmit() {
    const { name, phone, store } = this.data.formData;
    // 基本验证：姓名和手机号必填
    const canSubmit = name.length > 0 && phone.length === 11;
    this.setData({ canSubmit });
  },

  onSubmit() {
    if (!this.data.canSubmit) {
      wx.showToast({ title: '请完善信息', icon: 'none' });
      return;
    }

    // 表单数据
    const userInfo = {
      ...this.data.formData,
      openid: app.globalData.openid
    };

    // TODO: 调用API绑定用户（预留接口）
    apiService.bindUser(
      app.globalData.openid,
      userInfo,
      this.data.deviceInfo,
      null // 已验配路径暂无听力图文件
    ).then(res => {
      console.log('绑定成功', res);

      // 存储本地
      wx.setStorageSync('userInfo', userInfo);
      wx.setStorageSync('bindStatus', true);

      // 跳转到绑定确认页
      wx.redirectTo({
        url: `/pages/device-bind/device-bind?sn=${this.data.deviceInfo.sn}`
      });
    }).catch(err => {
      console.error('绑定失败', err);
      wx.showToast({ title: '绑定失败，请重试', icon: 'none' });
    });
  }
});
```

