```javascript
// 听力图上传页逻辑
const apiService = require('../../services/api-service');
const app = getApp();

Page({
  data: {
    audiogramPath: '',
    audiogramCloudPath: ''
  },

  onChooseImage() {
    wx.chooseImage({
      count: 1,
      sizeType: ['compressed'],
      sourceType: ['album', 'camera'],
      success: res => {
        console.log('选择图片成功', res);
        this.data.audiogramPath = res.tempFilePaths[0];
        this.setData({ audiogramPath: this.data.audiogramPath });
      },
      fail: err => {
        console.error('选择图片失败', err);
        wx.showToast({ title: '请选择图片', icon: 'none' });
      }
    });
  },

  onPreviewImage() {
    wx.previewImage({
      urls: [this.data.audiogramPath]
    });
  },

  onPreviewExample() {
    // 预览示例图
    wx.previewImage({
      urls: ['/assets/audiogram-example.png']
    });
  },

  onNext() {
    if (!this.data.audiogramPath) {
      wx.showToast({ title: '请先上传听力图', icon: 'none' });
      return;
    }

    wx.showLoading({ title: '上传中...' });

    // 上传到云存储（暂时用本地存储）
    wx.cloud.uploadFile({
      cloudPath: `audiogram/${app.globalData.openid}_${Date.now()}.jpg`,
      filePath: this.data.audiogramPath,
      success: res => {
        console.log('上传成功', res);
        this.data.audiogramCloudPath = res.fileID;
        wx.hideLoading();

        // TODO: 调用API保存听力图路径（预留接口）
        apiService.updateAudiogram(
          app.globalData.openid,
          res.fileID
        ).then(() => {
          // 存储到全局
          app.globalData.audiogramPath = res.fileID;

          // 跳转设备连接页（未验配路径）
          wx.redirectTo({
            url: '/pages/device-scan/device-scan?fitted=false'
          });
        }).catch(err => {
          console.error('保存听力图失败', err);
          // 继续流程，只是API调用失败
          wx.redirectTo({
            url: '/pages/device-scan/device-scan?fitted=false'
          });
        });
      },
      fail: err => {
        wx.hideLoading();
        console.error('上传失败', err);
        // 暂时允许继续（本地调试模式）
        app.globalData.audiogramPath = this.data.audiogramPath;
        wx.redirectTo({
          url: '/pages/device-scan/device-scan?fitted=false'
        });
      }
    });
  }
});
