// 首页逻辑
const app = getApp();

Page({
  data: {
    userInfo: null,
    deviceInfo: null,
    hasAudiogram: false
  },

  onShow() {
    // 刷新数据
    this.data.userInfo = wx.getStorageSync('userInfo') || {};
    this.data.deviceInfo = app.globalData.deviceInfo || {};
    this.data.hasAudiogram = this.data.deviceInfo?.hasAudiogram || false;

    this.setData({
      userInfo: this.data.userInfo,
      deviceInfo: this.data.deviceInfo,
      hasAudiogram: this.data.hasAudiogram
    });
  },

  onRemoteFitting() {
    if (!this.data.hasAudiogram) {
      wx.showModal({
        title: '提示',
        content: '您尚未完成验配，请先联系客服预约远程验配服务',
        showCancel: false
      });
      return;
    }
    // TODO: 跳转远程验配页（后续实现）
    wx.showToast({ title: '功能开发中', icon: 'none' });
  },

  onSelfFitting() {
    if (!this.data.hasAudiogram) {
      wx.showModal({
        title: '提示',
        content: '您尚未完成验配，请先完成验配后再使用自主验配功能',
        showCancel: false
      });
      return;
    }
    // TODO: 跳转自主验配页（后续实现）
