        /// </summary>
        /// <param name="dto"></param>
        /// <returns></returns>
        [HttpPost("login")]
        //public IActionResult Login([FromBody] LoginDto dto)
        public async Task<IActionResult> Login(LoginDto dto)
        {
            // 1. 验证用户 (调用 Service 层)
            var user = await _userService.GetUserInfo(dto.Account, dto.Password);
            if (user == null)
            {
                return BadRequest(ApiResponse<string>.Fail("用户名或密码错误", 401));
            }

            // 2. 生成 JWT Token
            string token = _tokenService.GenerateToken(user.Id, user.UserName, null);

            //UserDto userDto = Mapper.Map<UserDto>(user);

            var responseDto = new LoginResponseDto
            {
                Token = token,
                ExpiresIn = 7200, // 秒
                //userDto= Mapper.Map<UserDto>(user),
                userDto = new UserDto
                {
                    Id = user.Id,
                    UserName = user.UserName,
                    Account = user.Account,
                }
            };

            return Ok(ApiResponse<LoginResponseDto>.Success(responseDto, "登录成功"));
            //return Ok(ApiResponse<string>.Success(token, "登录成功"));
            //return Ok(new { code = 200, msg = "Login Success", token = token, data= JsonConvert.SerializeObject(dto)});
        }
        /// <summary>
        /// 登录
        /// </summary>
        /// <param name="dto"></param>
        /// <returns></returns>
        [HttpPost("wxlogin")]
        public async Task<IActionResult> WxLogin(WxLoginDto dto)
        {

            var appId = _config["WeChat:AppId"];
            var secret = _config["WeChat:AppSecret"];
            var url = $"https://api.weixin.qq.com/sns/jscode2session?appid={appId}&secret={secret}&js_code={dto.Code}&grant_type=authorization_code";

            var wxRes = await _http.GetFromJsonAsync<WxCodeResult>(url);
            if (wxRes == null || string.IsNullOrEmpty(wxRes.Openid))
            {
                return BadRequest("微信登录失败：code无效");
            }

            var openId = wxRes.Openid;

            // 查询用户是否存在
            var user= await _userService.GetUserByOpenid(openId);
            if (user == null)
            {
                Random random = new Random();
                char[] letters = "abcdefghijklmnopqrstuvwxyz".ToCharArray(); // 小写字母数组
                string randomLetters = "";
                string randomNumbers = "";

                // 生成三个随机字母
                for (int i = 0; i < 3; i++)
                {
                    randomLetters += letters[random.Next(letters.Length)];
                }

                // 生成四个随机数字
                for (int i = 0; i < 4; i++)
                {
                    randomNumbers += random.Next(0, 10); // 生成0到9的随机数
                }

                // 组合字符串
                string result = randomLetters + randomNumbers;
                UserDto userDto = new UserDto
                {
                    OpenId = openId,
                    UserName = dto.Nickname,
                    Account = "user_"+ result,
                };
                var userReturn = await _userService.WxRegister(userDto);
                if(userReturn == null)
                {
                    return Ok(ApiResponse<LoginResponseDto>.Fail("微信注册账号失败，请稍后重试！"));
                }
                user = userReturn;


            }

            // 2. 生成 JWT Token
            string token = _tokenService.GenerateToken(user.Id, user.UserName, null);


            var responseDto = new LoginResponseDto
            {
                Token = token,
                ExpiresIn = 7200, // 秒
                userDto = new UserDto
                {
                    Id = user.Id,
                    UserName = user.UserName,
                    Account = user.Account,
                }
            };

            return Ok(ApiResponse<LoginResponseDto>.Success(responseDto, "登录成功"));
        }
        /// <summary>
        /// 注册
        /// </summary>
        /// <param name="userDto"></param>
        /// <returns></returns>
        [HttpPost("register")]
        public async Task<IActionResult> Register(UserDto userDto)
        {
            if (await _userService.Register(userDto))
            {
                return Ok(ApiResponse<LoginResponseDto>.Success(null,"登录成功"));
            }
            else
            {
                return Ok(ApiResponse<LoginResponseDto>.Fail("账号注册失败，请稍后重试！"));
            }
        }

    }

    public record LoginResponseDto
    {
        public string Token { get; set; } = string.Empty;
        public int ExpiresIn { get; set; }
        public UserDto userDto { get; set; } = new();
    }
    // 微信返回
    class WxCodeResult
    {
        public string Openid { get; set; } = string.Empty;
        public string Session_key { get; set; } = string.Empty;
        public string? Unionid { get; set; }
        public int Errcode { get; set; }
        public string? Errmsg { get; set; }
    }

}

