const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
        Header, Footer, AlignmentType, LevelFormat, HeadingLevel, BorderStyle,
        WidthType, ShadingType, VerticalAlign, PageNumber, PageBreak } = require('docx');
const fs = require('fs');

// 表格样式辅助函数
const tableBorder = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const cellBorders = { top: tableBorder, bottom: tableBorder, left: tableBorder, right: tableBorder };
const headerShading = { fill: "D5E8F0", type: ShadingType.CLEAR };
const altRowShading = { fill: "F5F5F5", type: ShadingType.CLEAR };

// 创建表头单元格
function headerCell(text, width) {
  return new TableCell({
    borders: cellBorders,
    width: { size: width, type: WidthType.DXA },
    shading: headerShading,
    verticalAlign: VerticalAlign.CENTER,
    children: [new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold: true, size: 20 })]
    })]
  });
}

// 创建数据单元格
function dataCell(text, width, isAlt = false) {
  return new TableCell({
    borders: cellBorders,
    width: { size: width, type: WidthType.DXA },
    shading: isAlt ? altRowShading : { fill: "FFFFFF", type: ShadingType.CLEAR },
    children: [new Paragraph({
      children: [new TextRun({ text: text || "", size: 20 })]
    })]
  });
}

// 创建接口表格
function createApiTable(apis, colWidths = [1500, 2000, 1500, 4360]) {
  const rows = [
    new TableRow({
      tableHeader: true,
      children: [
        headerCell("接口名称", colWidths[0]),
        headerCell("请求方式", colWidths[1]),
        headerCell("接口路径", colWidths[2]),
        headerCell("说明", colWidths[3])
      ]
    })
  ];

  apis.forEach((api, idx) => {
    rows.push(new TableRow({
      children: [
        dataCell(api.name, colWidths[0], idx % 2 === 1),
        dataCell(api.method, colWidths[1], idx % 2 === 1),
        dataCell(api.path, colWidths[2], idx % 2 === 1),
        dataCell(api.desc, colWidths[3], idx % 2 === 1)
      ]
    }));
  });

  return new Table({
    columnWidths: colWidths,
    margins: { top: 100, bottom: 100, left: 180, right: 180 },
    rows: rows
  });
}

// 创建请求/响应表格
function createRequestResponseTable(items, colWidths = [2500, 2500, 4360]) {
  const rows = [
    new TableRow({
      tableHeader: true,
      children: [
        headerCell("参数名", colWidths[0]),
        headerCell("类型", colWidths[1]),
        headerCell("说明", colWidths[2])
      ]
    })
  ];

  items.forEach((item, idx) => {
    rows.push(new TableRow({
      children: [
        dataCell(item.name, colWidths[0], idx % 2 === 1),
        dataCell(item.type, colWidths[1], idx % 2 === 1),
        dataCell(item.desc, colWidths[2], idx % 2 === 1)
      ]
    }));
  });

  return new Table({
    columnWidths: colWidths,
    margins: { top: 100, bottom: 100, left: 180, right: 180 },
    rows: rows
  });
}

const doc = new Document({
  styles: {
    default: { document: { run: { font: "Arial", size: 22 } } },
